	}
	return "[" + strings.Join(params, ", ") + "]"
}

func isInterface(pkg *packages.Package, expr ast.Expr) bool {
	t := pkg.TypesInfo.TypeOf(expr)
	if t == nil {
		return false
	}
	_, ok := t.Underlying().(*types.Interface)
	return ok
